import React, { useState, useMemo, useEffect, useRef } from 'react';
import DataTable from '../../components/common/DataTable';
import Icon from '../../components/common/Icon';
import { icons } from '../../config/icons';
import apiService from '../../services/api.service';
import api from '../../api/api';
import { FormInput, FormTextarea } from '../../components/common/FormFields';
import useForm from '../../hooks/useForm';
import { useModal } from '../../context/ModalContext';
import { useNotifier } from '../../context/NotificationContext';

const BASE_URL = process.env.REACT_APP_API_BASE_URL || '';

const projectSchema = {
    title: { required: true, label: 'Title' }
};

const ProjectForm = ({ item, onSave, onClose, onRefresh, resourceFolder = 'projects' }) => {
    const { notify } = useNotifier();
    const { openPopup, closePopup } = useModal();
    const isEditMode = Boolean(item);

    // 1. Initial Values and Form Hook
    const initialValues = useMemo(() => ({
        title: item?.title || '',
        subtitle: item?.subtitle || '',
        venue: item?.venue || '',
        dated: item?.dated ? (() => {
            const d = new Date(item.dated);
            return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
        })() : '',
        remarks: item?.remarks || ''
    }), [item]);

    const { values, errors, handleChange, handleSubmit, registerRef } = useForm(initialValues, projectSchema);

    // 2. Media Gallery State
    const [existingMedia, setExistingMedia] = useState([]);
    const [mediaToDelete, setMediaToDelete] = useState(new Set());
    const [stagedFiles, setStagedFiles] = useState([]);
    const [loadingMedia, setLoadingMedia] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [savingProgress, setSavingProgress] = useState(null);
    const fileInputRef = useRef(null);

    // 3. Load existing media (Edit Mode Only)
    useEffect(() => {
        if (isEditMode && item?.id) {
            setLoadingMedia(true);
            api.get(`/api/${resourceFolder}/${item.id}/media`)
                .then(res => {
                    const files = res.data.files || res.data.data || [];
                    setExistingMedia(files);
                })
                .catch(err => console.error('Failed to load media', err))
                .finally(() => setLoadingMedia(false));
        }
    }, [isEditMode, item?.id, resourceFolder]);

    const handleFileUpload = (e) => {
        const files = Array.from(e.target.files);
        const newStaged = files.map(file => ({
            file,
            name: file.name,
            url: URL.createObjectURL(file),
            type: file.type.startsWith('video') ? 'video' : 'photo',
            isStaged: true
        }));
        setStagedFiles(prev => [...prev, ...newStaged]);
        e.target.value = '';
    };

    const handleDeleteMedia = (file) => {
        if (file.isStaged) {
            setStagedFiles(prev => prev.filter(f => f.url !== file.url));
            URL.revokeObjectURL(file.url);
        } else {
            setMediaToDelete(prev => {
                const next = new Set(prev);
                if (next.has(file.name)) next.delete(file.name);
                else next.add(file.name);
                return next;
            });
        }
    };

    const handleFormSubmit = async (formValues) => {
        setIsSubmitting(true);
        setSavingProgress('Saving project details...');
        try {
            // First save the project details
            const response = await onSave(formValues, item?.id);

            // Check if response is successful (onSave typically returns { success: true, itemId })
            if (response && response.success) {
                const resourceId = item?.id || response.itemId;

                if (!resourceId) throw new Error('Resource ID not found after save');

                const tasks = [];

                // Delete media if any marked for deletion
                if (mediaToDelete.size > 0 && item?.id) {
                    setSavingProgress(`Cleaning up ${mediaToDelete.size} media item(s)...`);
                    tasks.push(api.post(`/api/${resourceFolder}/${resourceId}/media/bulk-delete`, {
                        filenames: Array.from(mediaToDelete)
                    }));
                }

                // Upload staged files if any
                if (stagedFiles.length > 0) {
                    setSavingProgress(`Uploading ${stagedFiles.length} file(s)...`);
                    const uploadData = new FormData();
                    stagedFiles.forEach(s => uploadData.append('files', s.file));

                    tasks.push(api.post(`/api/${resourceFolder}/${resourceId}/media`, uploadData, {
                        headers: { 'Content-Type': 'multipart/form-data' }
                    }));
                }

                if (tasks.length > 0) await Promise.all(tasks);

                setSavingProgress('Finalizing...');
                if (onRefresh) onRefresh();
                if (onClose) onClose();
            }
        } catch (error) {
            console.error('Submission error:', error);
            const serverMessage = error.response?.data?.message;

            if (error.response?.status === 413) {
                // Specific "Too Large" Alert Popup
                openPopup({
                    title: 'Size Limit Exceeded',
                    widthClass: 'w-md',
                    content: (
                        <div className='alert-wrap'>
                            <div className='alert-icon danger-color'><Icon icon={icons.fileWarning} size={48} /></div>
                            <div className='alert-title'><h2>File Too Large</h2></div>
                            <div className='alert-content'>
                                <p>{serverMessage || 'One or more files are too large to be processed. Please resize your media and try again.'}</p>
                            </div>
                        </div>
                    ),
                    actions: [{ text: 'I Understand', className: 'btn-primary', onClick: closePopup }]
                });
            } else {
                notify({ message: `Failed to save project: ${serverMessage || error.message}`, style: 'error' });
            }
        } finally {
            setIsSubmitting(false);
            setSavingProgress(null);
        }
    };

    return (
        <form className='form-case' id="admin_resource_form" onSubmit={handleSubmit(handleFormSubmit)} noValidate>
            <div className='form-row-fx'>
                <div className='w7-fx'>
                    <FormInput label="Project Title" name="title" value={values.title} error={errors.title} onChange={handleChange} required inputRef={registerRef('title')} />
                </div>
                <div className='w3-fx'>
                    <FormInput label="Date" name="dated" type="date" value={values.dated} error={errors.dated} onChange={handleChange} inputRef={registerRef('dated')} />
                </div>
            </div>
            <FormInput label="Subtitle (Optional)" name="subtitle" value={values.subtitle} onChange={handleChange} placeholder="e.g. Community Outreach Program" />
            <FormInput label="Venue" name="venue" value={values.venue} onChange={handleChange} placeholder="Locality or Office Address" iconLeft={icons.mapPin} />
            <FormTextarea label="Remarks / Description" name="remarks" value={values.remarks} onChange={handleChange} rows={4} placeholder="Briefly describe the project..." />
            <div className='form-media-case'>
                <div className='form-media-grid'>
                    {loadingMedia ? (<div className='media-loader'>Loading media...</div>) : (
                        <>
                            {existingMedia.filter(f => !mediaToDelete.has(f.name)).map((file, idx) => (
                                <div key={`existing-${idx}`} className='form-media-item'>
                                    {file.type === 'photo' ? (
                                        <img src={`${BASE_URL}${file.url}`} alt={file.name} onClick={() => window.open(`${BASE_URL}${file.url}`, '_blank')} />
                                    ) : (
                                        <>
                                            <video src={`${BASE_URL}${file.url}#t=0.1`} preload="metadata" onClick={() => window.open(`${BASE_URL}${file.url}`, '_blank')} />
                                            <div className='form-media-video-icon'><Icon icon={icons.video} /></div>
                                        </>
                                    )}
                                    <div className='form-media-item-nav'>
                                        <button type='button' className='btn-danger' onClick={() => handleDeleteMedia(file)} title="Remove"><Icon icon={icons.times} /></button>
                                    </div>
                                </div>
                            ))}
                            {stagedFiles.map((file, idx) => (
                                <div key={`staged-${idx}`} className='form-media-item staged'>
                                    {file.type === 'photo' ? (
                                        <img src={file.url} alt={file.name} onClick={() => window.open(file.url, '_blank')} />
                                    ) : (
                                        <>
                                            <video src={`${file.url}#t=0.1`} preload="metadata" onClick={() => window.open(file.url, '_blank')} />
                                            <div className='video-thumb' style={{ pointerEvents: 'none' }}><Icon icon={icons.video} /></div>
                                        </>
                                    )}
                                    <div className="staged-badge">New</div>
                                    <div className='form-media-item-nav'>
                                        <button type='button' className='btn-danger' onClick={() => handleDeleteMedia(file)}><Icon icon={icons.times} /></button>
                                    </div>
                                </div>
                            ))}
                        </>
                    )}
                    <div className={`form-media-upload ${isSubmitting ? 'disabled' : ''}`} onClick={() => !isSubmitting && fileInputRef.current.click()}>
                        <Icon icon={icons.plusSquare} />
                        <p>{isSubmitting ? 'Processing...' : 'Add Image /Video'}</p>
                        <input type="file" ref={fileInputRef} style={{ display: 'none' }} multiple onChange={handleFileUpload} accept="image/*,video/*" disabled={isSubmitting} />
                    </div>
                </div>
            </div>
            {/* Progress Overlay */}
            {savingProgress && (
                <div className="form-saving-overlay">
                    <div className="form-saving-content">
                        <div className="loader-line-scale"><div></div><div></div><div></div><div></div><div></div></div>
                        <p>{savingProgress}</p>
                    </div>
                </div>
            )}
        </form>
    );
};

function ProjectCardGrid({ data, handleEditClick, handleDelete }) {
    return (
        <div className='grid-case'>
            {data.map(item => (
                <div key={item.id} className="card-case">
                    <div className='card-image'>
                        {item.coverImage ? (
                            <div className='card-image-file'><img src={`${BASE_URL}${item.coverImage}`} alt={item.title} /></div>
                        ) : item.coverVideo ? (
                            <div className='card-image-file video-thumb'>
                                <video src={`${BASE_URL}${item.coverVideo}#t=0.1`} preload="metadata" muted />
                            </div>
                        ) : (
                            <div className='card-image-placeholder'><Icon icon={icons.fileImage} /> No Cover Image</div>
                        )}
                        <div className='card-media-badge-case'>
                            {item.hasPhotos && <div className='card-media-badge'><Icon icon={icons.fileImage} /></div>}
                            {item.hasVideos && <div className='card-media-badge'><Icon icon={icons.video} /></div>}
                        </div>
                    </div>
                    <div className='card-body'>
                        <div className='card-info'>
                            <h3 className='no-wrap'>{item.title}</h3>
                            {item.subtitle && <p className='card-subtitle'>{item.subtitle}</p>}
                        </div>
                        <div className='card-meta'>
                            <span><Icon icon={icons.mapPin} /> {item.venue || 'No venue'}</span>
                            <span><Icon icon={icons.calendar} /> {item.dated ? new Date(item.dated).toLocaleDateString() : 'No date'}</span>
                        </div>
                        <div className='card-foot no-pad pad10-top border-top space-between'>
                            <button type='button' className='button flat btn-warning' onClick={() => handleEditClick(item)}><Icon icon={icons.edit} /> Edit</button>
                            <button type='button' className='button flat btn-danger' onClick={() => handleDelete(item.id, item.title)}><Icon icon={icons.delete} /> Delete</button>
                        </div>
                    </div>
                </div>
            ))}
        </div>
    );
}

const CustomControls = ({ limit, onLimitChange, searchTerm, onSearchChange, onFilterChange, onRefresh, totalRecords = 0, activeFilters = {} }) => {
    return (
        <div className='pagelet'>
            <div className='pagelet-body'>
                <div className='table-custom-case'>
                    <div className='table-custom-controls'>
                        <div className='table-limit'>
                            <p>Show</p>
                            <select name='custom-limit' value={limit} onChange={(e) => onLimitChange(e.target.value)}>
                                <option value={10}>10</option>
                                <option value={25}>25</option>
                                <option value={50}>50</option>
                                <option value={100}>100</option>
                            </select>
                            <p>Entries</p>
                        </div>

                        <div className='table-action'>
                            <div className='table-data-count'>{totalRecords.toLocaleString()}<b> Item{totalRecords !== 1 ? 's' : ''}</b></div>
                            <div className='table-search'>
                                <Icon icon={icons.search} />
                                <input name='custom-search' type='search' placeholder='Search...' autoComplete='off' value={searchTerm} onChange={(e) => onSearchChange(e.target.value)} />
                            </div>
                            <button className='button icon' onClick={onRefresh} title='Refresh'><Icon icon={icons.refresh} /></button>
                        </div>
                    </div>

                    <div className='table-custom-filters bordered-top show'>
                        <div className='table-filters'> <p>Venue</p>
                            <input type='text' name='venue_filter' placeholder='Filter by Venue...' value={activeFilters.venue || ''} onChange={(e) => onFilterChange('venue', e.target.value)} />
                        </div>
                        <div className='table-filters'> <p>Date</p>
                            <input type='date' name='date_filter' value={activeFilters.dated || ''} onChange={(e) => onFilterChange('dated', e.target.value)} />
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const TableDataGrid = () => {
    const columns = [
        { key: 'title', label: 'Projects', type: 0, sortable: true, render: (item) => (<div className="tr-name"><b>{item.title}</b>{item.subtitle && <p>{item.subtitle}</p>}</div>) },
        { key: 'media', label: 'Media', type: 1, render: (item) => (<div className='proj-media'>{item.hasPhotos && <span title="Has Photos"><Icon icon={icons.fileImage} /></span>}{item.hasVideos && <span title="Has Videos"><Icon icon={icons.video} /></span>}{!item.hasPhotos && !item.hasVideos && <span style={{ opacity: 0.2 }}><Icon icon={icons.fileQuestion} /></span>}</div>) },
        { key: 'dated', label: 'Date', type: 1, sortable: true, render: (item) => item.dated ? new Date(item.dated).toLocaleDateString() : 'N/A' },
        { key: 'venue', label: 'Venue', type: 1, sortable: true },
        { key: 'remarks', label: 'Remarks', type: 1, class: 'td-remarks' }
    ];

    const config = useMemo(() => ({
        title: <span><h2>Project DataGrid</h2><p>Table + Grid View Implementation</p></span>,
        headerActions: [],
        defaultSortBy: 'dated',
        defaultSortOrder: 'desc',
        searchables: ['title', 'subtitle', 'venue', 'remarks'],
        modalWidth: 'w-mm',
        manualClose: true,
        tableControls: false,
        customControls: <CustomControls />
    }), []);

    return (
        <DataTable
            resourceName="Project"
            apiService={apiService.projects}
            columns={columns}
            FormComponent={ProjectForm}
            formProps={{
                resourceFolder: 'projects'
            }}
            config={config}
            gridView={<ProjectCardGrid />}
        />
    );
};

export default TableDataGrid;